import { useState } from 'react';
import './App.css';
import './components/Header.jsx';

const projects = [
  { title: "Project One", description: "A short line about what this is.", year: "2025" },
  { title: "Project Two", description: "Another thing you made or worked on.", year: "2024" },
  { title: "Project Three", description: "Keep these descriptions tight.", year: "2024" },
];

function App() {

  return (
    <div className="container">

      <Header />

      {/* Header */}
      <header className="header">
        <span className="name">Your Name</span>
        <nav className="nav">
          <a href="#work">Work</a>
          <a href="#about">About</a>
          <a href="mailto:you@email.com">Contact</a>
        </nav>
      </header>

      {/* Hero */}
      <section className="hero">
        <h1 className="hero-title">Making things,<br />with intention.</h1>
        <p className="hero-sub">Designer, builder, whatever you want to call it.</p>
      </section>

      {/* Work */}
      <section className="work" id="work">
        {projects.map((project, i) => (
          <div
            key={i}
            className={`project-row ${hovered !== null && hovered !== i ? 'dimmed' : ''}`}
            onMouseEnter={() => setHovered(i)}
            onMouseLeave={() => setHovered(null)}
          >
            <span className="project-title">{project.title}</span>
            <span className="project-desc">{project.description}</span>
            <span className="project-year">{project.year}</span>
          </div>
        ))}
      </section>

      {/* About */}
      <section className="about" id="about">
        <p>
          A few sentences about you — what you do, what you care about,
          what you're working toward. Keep it short and real.
        </p>
      </section>

      {/* Footer */}
      <footer className="footer">
        <span>© 2026</span>
        <a href="https://linkedin.com" target="_blank" rel="noreferrer">LinkedIn</a>
      </footer>

    </div>
  );
}

export default App;
